import React, { useEffect, useState } from 'react'
import Header from './Header';
import { test_img } from '../assets/img';

export const Game = () => {
    const [imgWidth, setImgWidth] = useState(0)
    const [imgHeight, setImgHeight] = useState(0)

  return (
    <div className='flex flex-col h-screen'>
        <Header/>
        <div className='flex flex-1 w-full justify-center overflow-hidden'>
            <img src={test_img} className=' h-full object-contain'
            onLoad={
                (e) => {
                    setImgWidth(e.currentTarget.width)
                    setImgHeight(e.currentTarget.height)
                }
            }
            />
        </div>

        <TextBox width={imgWidth} height={imgHeight} text={"hello"}></TextBox>

    </div>
  )
}
const TextBox = ({height, width, name, text, speed}) => {

    const [currentText, setCurrentText] = useState("")
    const [textIndex, setTextIndex] = useState(0)

    useEffect(() => {
        setCurrentText("")

        const typingWord = setInterval(() => {
            setTextIndex(prevIndex => {
                if(prevIndex < text.length) {
                    setCurrentText(text.slice(0, prevIndex + 1))
                    console.log(textIndex)
                    console.log(text.slice(0, textIndex))
                } else {
                    clearInterval(typingWord);
                    return prevIndex;
                }
            })
            // console.log(currentText)
            // console.log("here")            
        }, speed)

        return () => clearInterval(typingWord); 
    }, [speed, text])

    return (
        <div className="fixed h-16 bg-[rgba(128,128,255,0.5)] blur-md  bottom-0 left-1/2 -translate-x-1/2"
        style={{
            width: `${width}px`,
            height: `${height/3}px`
        }}
        >
            <p>{currentText}</p>
        </div>
    )
}

export default Game;
